const item = $input.first();
const raw = item.json;
const body = raw.body !== undefined ? raw.body : raw;
const parsed = typeof body === 'string' ? JSON.parse(body) : (body || {});
let order_invoice_number = parsed.order_invoice_number || parsed.order?.order_invoice_number || '';
order_invoice_number = String(order_invoice_number).trim();
// Normalize to DB format YYYYMMDD-NNNN (e.g. 202602230001 -> 20260223-0001)
if (/^\d{8}\d{4}$/.test(order_invoice_number)) {
  order_invoice_number = order_invoice_number.slice(0, 8) + '-' + order_invoice_number.slice(8);
}
const transaction_id = parsed.transaction_id || parsed.transaction?.transaction_id || 'ipn';
return [{ json: { order_invoice_number, transaction_id: String(transaction_id) } }];

const upd = $input.first().json;
const unpaid = $('Get Unpaid Order').first().json;
const procs = Array.isArray(unpaid.pending_procedures) ? unpaid.pending_procedures : [];
const paid_at = upd.paid_at || new Date().toISOString();
const order_id = upd.id;
return procs.map(p => ({ json: {
  order_id,
  procedure_id: p.id != null ? p.id : null,
  procedure_name: p.name || p.procedure_name || 'Procedure',
  room_number: String(p.room || p.room_number || ''),
  amount: Number(p.price) || 0,
  paid_at,
  state: 'pending'
}}));

const item = $input.first();
const d = item.json;
const fmtVnd = (n) => (n != null ? new Intl.NumberFormat('vi-VN', { maximumFractionDigits: 0 }).format(Number(n)) + ' ₫' : '—');
const fmtTime = (s) => { if (!s) return '—'; try { const dt = new Date(s); return dt.toLocaleString('vi-VN', { timeZone: 'Asia/Ho_Chi_Minh', dateStyle: 'medium', timeStyle: 'short' }); } catch { return String(s); } };
return [{ json: { email: d.email || '', orderNumber: d.order_number || '', userName: d.user_name || 'Customer', procedureName: d.procedure_name || '—', roomNumber: d.room_number || '—', totalAmount: fmtVnd(d.total_amount), paidAt: fmtTime(d.paid_at), createdAt: fmtTime(d.created_at) } }];
